import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

/**
 * Tests for the issue: False positive at multiline-if-else when using "else if"
 * where `else if () { }` gets formatted to `else { if () { } }`
 */
class MultiLineIfElseRuleTestElseIf {
    private val multiLineIfElseRuleAssertThat = assertThatRule { MultiLineIfElseRule() }

    @Test
    fun `Issue - Given else-if with braces followed by elvis operator should not be wrapped`() {
        val code =
            """
            val x = if (showFilter) {
                1
            } else if (activeTabIndex == 0) {
                2
            } else {
                null
            } ?: 0
            """.trimIndent()
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Issue - Given else-if with braces followed by method call should not be wrapped`() {
        val code =
            """
            val foo = if (bar1) {
                "bar1"
            } else if (bar2) {
                "bar2"
            } else {
                "bar3"
            }.plus("foo")
            """.trimIndent()
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Issue - Given nested else-if with braces should not be wrapped`() {
        val code =
            """
            val x = if (a) {
                1
            } else if (b) {
                2
            } else if (c) {
                3
            } else {
                4
            }
            """.trimIndent()
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Issue - Given multiline else-if all with braces should not be wrapped`() {
        val code =
            """
            fun test(): Int {
                return if (condition1) {
                    value1
                } else if (condition2) {
                    value2
                } else {
                    value3
                }
            }
            """.trimIndent()
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }
}
