import com.pinterest.ktlint.rule.engine.core.api.RuleId
import com.pinterest.ktlint.rule.engine.core.api.RuleProvider
import org.jetbrains.kotlin.com.intellij.lang.ASTNode
import org.junit.jupiter.api.Test

class MultiLineIfElseDebugTest {

    @Test
    fun `Debug - print AST for else if with elvis`() {
        val code = """
            val x = if (showFilter) {
                1
            } else if (activeTabIndex == 0) {
                2
            } else {
                null
            } ?: 0
        """.trimIndent()

        val rule = object : Rule(
            ruleId = RuleId("standard:debug-rule"),
            about = About()
        ) {
            override fun beforeVisitChildNodes(
                node: ASTNode,
                autoCorrect: Boolean,
                emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
            ) {
                if (node.elementType == ELSE) {
                    println("=== ELSE node ===")
                    println("  text: ${node.text.take(50)}...")
                    println("  firstChildNode: ${node.firstChildNode}")
                    println("  firstChildNode?.elementType: ${node.firstChildNode?.elementType}")

                    if (node.firstChildNode?.elementType == IF) {
                        val innerIf = node.firstChildNode
                        println("  innerIf: $innerIf")
                        println("  innerIf.findChildByType(THEN): ${innerIf?.findChildByType(THEN)}")
                        val thenNode = innerIf?.findChildByType(THEN)
                        println("  thenNode?.firstChildNode: ${thenNode?.firstChildNode}")
                        println("  thenNode?.firstChildNode?.elementType: ${thenNode?.firstChildNode?.elementType}")
                        println("  thenNode?.findChildByType(BLOCK): ${thenNode?.findChildByType(BLOCK)}")
                    }
                }
            }
        }

        KtLintRuleEngine(
            ruleProviders = setOf(
                RuleProvider { rule }
            )
        ).lint(Code.fromSnippet(code))
    }

    @Test
    fun `Debug - print AST for else if without elvis`() {
        val code = """
            val x = if (a) {
                1
            } else if (b) {
                2
            } else if (c) {
                3
            } else {
                4
            }
        """.trimIndent()

        val rule = object : Rule(
            ruleId = RuleId("standard:debug-rule"),
            about = About()
        ) {
            override fun beforeVisitChildNodes(
                node: ASTNode,
                autoCorrect: Boolean,
                emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
            ) {
                if (node.elementType == ELSE) {
                    println("=== ELSE node ===")
                    println("  text: ${node.text.take(50)}...")
                    println("  firstChildNode: ${node.firstChildNode}")
                    println("  firstChildNode?.elementType: ${node.firstChildNode?.elementType}")

                    if (node.firstChildNode?.elementType == IF) {
                        val innerIf = node.firstChildNode
                        println("  innerIf: $innerIf")
                        println("  innerIf.findChildByType(THEN): ${innerIf?.findChildByType(THEN)}")
                        val thenNode = innerIf?.findChildByType(THEN)
                        println("  thenNode?.firstChildNode: ${thenNode?.firstChildNode}")
                        println("  thenNode?.firstChildNode?.elementType: ${thenNode?.firstChildNode?.elementType}")
                        println("  thenNode?.findChildByType(BLOCK): ${thenNode?.findChildByType(BLOCK)}")
                    }
                }
            }
        }

        KtLintRuleEngine(
            ruleProviders = setOf(
                RuleProvider { rule }
            )
        ).lint(Code.fromSnippet(code))
    }
}
