    /**
     * Finds an IF node that is either a direct child or wrapped in expression nodes like
     * BINARY_EXPRESSION (for elvis ?:), DOT_QUALIFIED_EXPRESSION (for method calls), etc.
     */
    private fun ASTNode.findIfNode(): ASTNode? {
        // First, check for direct IF child
        findChildByType(IF)?.let { return it }

        // Check for IF wrapped in expression nodes (e.g., `if (...) ?: 0` or `if (...).method()`)
        val expressionTypes = listOf(
            BINARY_EXPRESSION,
            DOT_QUALIFIED_EXPRESSION,
            SAFE_ACCESS_EXPRESSION,
            POSTFIX_EXPRESSION,
        )
        for (child in children()) {
            if (child.elementType in expressionTypes) {
                child.findChildByType(IF)?.let { return it }
            }
        }
        return null
    }
}

